    FOR v_item IN SELECT * FROM jsonb_array_elements(v_json_data)
    LOOP
        v_clean_name := trim(v_item->>'investor');

        -- 1. FIND OR CREATE INVESTOR
        SELECT id INTO v_investor_id FROM public.investors WHERE name ILIKE v_clean_name LIMIT 1;

        IF v_investor_id IS NULL THEN
            INSERT INTO public.investors (name, email, status, entity_type, created_at, updated_at)
            VALUES (
                v_clean_name, 
                lower(regexp_replace(left(v_clean_name, 20), '\W+', '.', 'g')) || '.' || substring(md5(random()::text) from 1 for 4) || '@placeholder.indigo.com',
                'active',
                'individual',
                NOW(),
                NOW()
            )
            RETURNING id INTO v_investor_id;
            RAISE NOTICE 'Created NEW Investor: %', v_clean_name;
        END IF;

        -- 2. PROCESS FUNDS
        FOR v_fund_item IN SELECT * FROM jsonb_array_elements(v_item->'funds')
        LOOP
            -- Map Fund Name
            CASE v_fund_item->>'fund'
                WHEN 'BTC YIELD FUND' THEN v_asset_symbol := 'BTC';
                WHEN 'ETH YIELD FUND' THEN v_asset_symbol := 'ETH';
                WHEN 'SOL YIELD FUND' THEN v_asset_symbol := 'SOL';
                WHEN 'USDT YIELD FUND' THEN v_asset_symbol := 'USDT';
                WHEN 'XRP YIELD FUND' THEN v_asset_symbol := 'XRP';
                ELSE v_asset_symbol := NULL;
            END CASE;

            IF v_asset_symbol IS NOT NULL THEN
                v_opening := (v_fund_item->>'beginning_balance')::NUMERIC;
                v_additions := (v_fund_item->>'additions')::NUMERIC;
                v_withdrawals := (v_fund_item->>'withdrawals')::NUMERIC;
                v_yield := (v_fund_item->>'yield_earned')::NUMERIC;
                v_closing := (v_fund_item->>'ending_balance')::NUMERIC;

                -- A. INSERT INTO investor_monthly_reports
                INSERT INTO public.investor_monthly_reports (
                    investor_id,
                    report_month,
                    asset_code,
                    opening_balance,
                    additions,
                    withdrawals,
                    yield_earned,
                    closing_balance,
                    created_at,
                    updated_at
                ) VALUES (
                    v_investor_id,
                    (v_item->>'month')::DATE,
                    v_asset_symbol,
                    v_opening,
                    v_additions,
                    v_withdrawals,
                    v_yield,
                    v_closing,
                    NOW(),
                    NOW()
                )
                ON CONFLICT (investor_id, report_month, asset_code) 
                DO UPDATE SET
                    opening_balance = EXCLUDED.opening_balance,
                    additions = EXCLUDED.additions,
                    withdrawals = EXCLUDED.withdrawals,
                    yield_earned = EXCLUDED.yield_earned,
                    closing_balance = EXCLUDED.closing_balance,
                    updated_at = NOW();

                -- B. UPSERT INTO investor_positions
                SELECT id INTO v_fund_id FROM public.funds WHERE asset_symbol = v_asset_symbol LIMIT 1;
                
                IF v_fund_id IS NOT NULL THEN
                    INSERT INTO public.investor_positions (
                        investor_id, 
                        fund_id, 
                        shares, 
                        current_value,
                        cost_basis, 
                        updated_at
                    )
                    VALUES (
                        v_investor_id,
                        v_fund_id,
                        v_closing, -- Shares = Balance
                        v_closing, -- Value = Balance (assuming 1.0 NAV for simplicity/tokens)
                        v_closing, -- Approximate cost basis
                        NOW()
                    )
                    ON CONFLICT (investor_id, fund_id) 
                    DO UPDATE SET
                        shares = EXCLUDED.shares,
                        current_value = EXCLUDED.current_value,
                        updated_at = NOW();
                END IF;

            END IF;
        END LOOP;
    END LOOP;
